1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: Damage[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type QuoteResult = { premium: number };
8	type ClaimResult = { payout: number };
9	type Result = QuoteResult | ClaimResult;
10	type Customer = { yearsWithMHPCO: number };
11	type ScenarioInput = { customer: Customer; steps: Step[] };
12	type ScenarioOutput = { results: Result[] };
13	
14	const COMPONENT_BASE_PREMIUM = 25;
15	const COMPONENT_BUNDLE_PREMIUM = 60;
16	const COMPONENT_BUNDLE_SIZE = 3;
17	const COMPONENT_TYPES = ["rune", "moonstone"];
18	const SAVINGS_PER_BUNDLE =
19	  COMPONENT_BUNDLE_SIZE * COMPONENT_BASE_PREMIUM - COMPONENT_BUNDLE_PREMIUM;
20	
21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: COMPONENT_BASE_PREMIUM,
27	  moonstone: COMPONENT_BASE_PREMIUM,
28	};
29	
30	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
31	const CURSED_SURCHARGE_PERCENT = 50;
32	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
33	const HIGH_ENCHANTMENT_THRESHOLD = 5;
34	const LOYALTY_DISCOUNT_PERCENT = 20;
35	const LOYALTY_THRESHOLD_YEARS = 2;
36	const REPEAT_CONTRACT_DISCOUNT_PERCENT = 15;
37	const PROCESSING_FEE = 5;
38	
39	const addSurchargePercent = (amount: number, percent: number): number =>
40	  (amount * (100 + percent)) / 100;
41	
42	const applyDiscountPercent = (amount: number, percent: number): number =>
43	  (amount * (100 - percent)) / 100;
44	
45	const addSurchargeIf = (amount: number, condition: boolean, percent: number): number =>
46	  condition ? addSurchargePercent(amount, percent) : amount;
47	
48	const applyDiscountIf = (amount: number, condition: boolean, percent: number): number =>
49	  condition ? applyDiscountPercent(amount, percent) : amount;
50	
51	const itemPremium = (item: Item): number => {
52	  const base = BASE_PREMIUMS[item.type];
53	  const withCursed = addSurchargeIf(base, item.cursed, CURSED_SURCHARGE_PERCENT);
54	  return addSurchargeIf(
55	    withCursed,
56	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
57	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
58	  );
59	};
60	
61	const sumItemPremiums = (items: Item[]): number =>
62	  items.reduce((sum, item) => sum + itemPremium(item), 0);
63	
64	const countItemsOfType = (items: Item[], type: string): number =>
65	  items.filter((item) => item.type === type).length;
66	
67	const bundlesOfType = (items: Item[], type: string): number =>
68	  Math.floor(countItemsOfType(items, type) / COMPONENT_BUNDLE_SIZE);
69	
70	const componentBundleDiscount = (items: Item[]): number =>
71	  COMPONENT_TYPES.reduce(
72	    (savings, type) => savings + bundlesOfType(items, type) * SAVINGS_PER_BUNDLE,
73	    0,
74	  );
75	
76	const applyContractAdjustment = (amount: number, isFirstQuote: boolean): number =>
77	  isFirstQuote
78	    ? addSurchargePercent(amount, FIRST_INSURANCE_SURCHARGE_PERCENT)
79	    : applyDiscountPercent(amount, REPEAT_CONTRACT_DISCOUNT_PERCENT);
80	
81	const applyLoyaltyDiscount = (amount: number, yearsWithMHPCO: number): number =>
82	  applyDiscountIf(amount, yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT_PERCENT);
83	
84	const itemsSubtotal = (items: Item[]): number =>
85	  sumItemPremiums(items) - componentBundleDiscount(items);
86	
87	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFirstQuote: boolean): number => {
88	  const afterContract = applyContractAdjustment(itemsSubtotal(items), isFirstQuote);
89	  const afterLoyalty = applyLoyaltyDiscount(afterContract, yearsWithMHPCO);
90	  return Math.ceil(afterLoyalty + PROCESSING_FEE);
91	};
92	
93	const CLAIM_DEDUCTIBLE = 100;
94	const DRAGON_MATERIAL = "dragon";
95	
96	const isFullyReimbursed = (item: Item): boolean => item.material === DRAGON_MATERIAL;
97	
98	const damageReimbursement = (damage: Damage, policyItems: Item[]): number => {
99	  const item = policyItems.find((i) => i.type === damage.itemType);
100	  return item && isFullyReimbursed(item) ? damage.amount : 0;
101	};
102	
103	const policyItemsFor = (steps: Step[], policyIndex: number): Item[] => {
104	  const policyStep = steps[policyIndex];
105	  return policyStep?.op === "quote" ? policyStep.items : [];
106	};
107	
108	const claimPayout = (claim: ClaimStep, policyItems: Item[]): number => {
109	  const grossReimbursement = claim.incident.damages.reduce(
110	    (sum, damage) => sum + damageReimbursement(damage, policyItems),
111	    0,
112	  );
113	  return Math.max(0, grossReimbursement - CLAIM_DEDUCTIBLE);
114	};
115	
116	const runStep = (step: Step, customer: Customer, steps: Step[], stepIndex: number): Result =>
117	  step.op === "claim"
118	    ? { payout: claimPayout(step, policyItemsFor(steps, step.policy)) }
119	    : { premium: quotePremium(step.items, customer.yearsWithMHPCO, stepIndex === 0) };
120	
121	export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
122	  results: input.steps.map((step, index) => runStep(step, input.customer, input.steps, index)),
123	});
