const CLAIM_DEDUCTIBLE = 100;
const DRAGON_MATERIAL = "dragon";
const REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
const PARTIAL_REIMBURSEMENT_PERCENT = 50;

const isFullyReimbursed = (item: Item): boolean => item.material === DRAGON_MATERIAL;

const isPartiallyReimbursed = (item: Item): boolean =>
  item.enchantment >= REIMBURSEMENT_ENCHANTMENT_THRESHOLD;

const damageReimbursement = (damage: Damage, policyItems: Item[]): number => {
  const item = policyItems.find((i) => i.type === damage.itemType);
  if (!item) return 0;
  if (isFullyReimbursed(item)) return damage.amount;
  if (isPartiallyReimbursed(item)) return (damage.amount * PARTIAL_REIMBURSEMENT_PERCENT) / 100;
  return 0;
};
